# Module: renderers - Concrete implementations of shapes from shapes module

from shapes import Shape, IDrawable
from geometry import Point, Color

class Circle(Shape):
    # Concrete circle implementation
    center: Point
    radius: float
    color: Color

    def __init__(self, center: Point, radius: float, color: Color):
        super().__init__("Circle")
        self.center = center
        self.radius = radius
        self.color = color

    @override
    def draw(self) -> str:
        return f"Drawing {self.name} at ({self.center.x}, {self.center.y}) with radius {self.radius}"

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def perimeter(self) -> float:
        return 2.0 * 3.14159 * self.radius

    @override
    def describe(self) -> str:
        base: str = super().describe()
        return f"{base}, {self.color.to_rgb_string()}"

class Rectangle(Shape):
    # Concrete rectangle implementation
    top_left: Point
    width: float
    height: float
    color: Color

    def __init__(self, corner: Point, width: float, height: float, color: Color):
        super().__init__("Rectangle")
        self.top_left = corner
        self.width = width
        self.height = height
        self.color = color

    @override
    def draw(self) -> str:
        return f"Drawing {self.name} at ({self.top_left.x}, {self.top_left.y}), {self.width} x {self.height}"

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

class ShapeFactory:
    # Factory for creating shapes
    @static
    def create_circle(x: float, y: float, radius: float) -> Circle:
        center: Point = Point(x, y)
        color: Color = Color(0, 0, 255)
        return Circle(center, radius, color)

    @static
    def create_rectangle(x: float, y: float, width: float, height: float) -> Rectangle:
        corner: Point = Point(x, y)
        color: Color = Color(255, 0, 0)
        return Rectangle(corner, width, height, color)
